INSERT INTO messages (id, session_id, request_id, role, mode, content, structured, agent, metadata, created_at) VALUES ('0b373322-465b-4e78-adc7-bf70eed7d519', 'b4d58fa4-f550-4646-a690-72f9fcdeca3a', NULL, 'user', 'comparison', '我想认真对比两款具体车型，请从空间、续航、智能化、保值率和售后成本几个维度帮我分析。', NULL, NULL, '{"importedFrom":"sessions.json","order":0}'::jsonb, '2026-03-26T06:28:13.126Z');
INSERT INTO messages (id, session_id, request_id, role, mode, content, structured, agent, metadata, created_at) VALUES ('407ec47a-64f0-4228-ba00-35455b469093', 'b4d58fa4-f550-4646-a690-72f9fcdeca3a', NULL, 'assistant', 'comparison', '您尚未指定需要对比的两款车型，请告诉我具体想对比哪两款车（如「小鹏 G6 vs 特斯拉 Model Y」或「小米 SU7 vs 极氪 007」），我才能基于空间、续航、智能化、保值率及售后成本等维度为您做详细分析。

**比较重点**
- 请补全两款具体车型
- 告诉我你的主要决策场景

**建议下一步**
1. 补充另一款车型
2. 说明你更看重家用、通勤还是长途

**推荐结论**
待您补充具体车型后，我将结合您关注的 ADAS、Range、Space 三大优先级，给出客观对比与购买建议。', NULL, NULL, '{"importedFrom":"sessions.json","order":1}'::jsonb, '2026-03-26T06:28:13.126Z');
INSERT INTO messages (id, session_id, request_id, role, mode, content, structured, agent, metadata, created_at) VALUES ('61c92b14-02a9-465d-af18-07ca7535e929', 'b4d58fa4-f550-4646-a690-72f9fcdeca3a', NULL, 'user', 'comparison', '小鹏 G6 vs 特斯拉 Model Y', NULL, NULL, '{"importedFrom":"sessions.json","order":2}'::jsonb, '2026-03-26T06:28:13.126Z');
INSERT INTO messages (id, session_id, request_id, role, mode, content, structured, agent, metadata, created_at) VALUES ('1ec37b1b-f338-4ccb-bc51-2681b8f3d58e', 'b4d58fa4-f550-4646-a690-72f9fcdeca3a', NULL, 'assistant', 'comparison', '两款中型纯电SUV标杆对决：小鹏G6以更低门槛提供长续航与本土高阶智驾，特斯拉Model Y则以品牌力与全球超充网络见长。

**比较重点**
- 重点诉求：ADAS / Range / Space

**维度对比**
- **价格**：A — 小鹏G6：约19.99万起，入门门槛低于Model Y约5万元，同续航版本价格优势明显；B — 特斯拉Model Y：约24.99万起，品牌溢价明显，但保值率与二手流通性通常更强
- **续航/能耗**：A — 小鹏G6：CLTC最高约755km（视配置），800V高压平台充电快，长途焦虑小；B — 特斯拉Model Y：CLTC常见约554–688km，能耗控制优秀，但续航上限略逊；超充网络覆盖广
- **智能化**：A — 小鹏G6：高阶智驾（城市/高速NGP）与座舱生态贴合国内场景，语音交互与导航体验本土化强；B — 特斯拉Model Y：Autopilot/FSD基础扎实，OTA更新频繁，但FSD国内功能尚未完全开放，语音与导航本土化略逊
- **空间/舒适**：A — 小鹏G6：中型SUV，后排腿部与头部空间充裕，座椅配置（通风/加热）通常更丰富；B — 特斯拉Model Y：前备厢+后备厢储物灵活，但后排座椅偏短硬，内饰极简，NVH控制一般

**建议下一步**
1. 如果你重视智驾和座舱，优先去试驾 小鹏 G6 与 特斯拉 Model Y
2. 把最在意的 2-3 个维度单独拎出来确认，不要一次比较过多信息
3. 继续补充：最重要的比较场景

**推荐结论**
推荐结论：预算20万左右、看重长续航与本土高阶智驾（尤其城市通勤）选小鹏G6；预算充足、看重品牌保值与全球超充网络、接受极简内饰选特斯拉Model Y。', NULL, NULL, '{"importedFrom":"sessions.json","order":3}'::jsonb, '2026-03-26T06:28:13.126Z');
