INSERT INTO messages (id, session_id, request_id, role, mode, content, structured, agent, metadata, created_at) VALUES ('032a911b-2c03-493b-9130-211d7b6f667f', '30cc1ebc-9702-4f15-aa6f-4540fd6b4332', NULL, 'assistant', 'service', '**小鹏G6家用场景深度体验指南**

先锁定预算、补能条件、家庭结构和通勤强度，再决定轿车/SUV、纯电/增程。

**操作步骤**
1. 通过小鹏汽车App或官网预约当地体验中心试驾，备注''家用场景体验''要求包含城市拥堵、快速路、地库泊车及后排乘坐环节
2. 到店优先验证空间实用性：让 tallest 家庭成员坐后排测量膝部与头部空间，检查后备箱开口高度及容积是否满足婴儿车/露营装备装载（G6为轿跑SUV，需重点确认后排头部空间）
3. 重点体验ADAS能力：要求销售演示城市NGP（如当地已开放）或高速NGP，观察拥堵跟车、变道决策及泊车对狭窄车位的适应能力（符合你对智驾的关注点）
4. 了解续航与补能：询问800V高压快充实际表现及你常用充电站的兼容性，结合你的通勤距离估算冬季实际续航（关注Range优先级）
5. 安全细节检查：查看车身刚性材料、气囊配置及主动安全功能演示，了解OTA升级对安全系统的持续优化能力（符合Safety关注点）
6. 若考虑对比：可要求门店安排小鹏G6与小米SU7或G9的连续体验，便于横向比较空间与智驾差异

**注意事项**
- 具体车型配置、价格、金融政策及属地化权益以小鹏汽车官网或当地授权门店最新信息为准，建议试驾前通过官方客服确认
- G6作为家用SUV，建议重点验证后排长途乘坐舒适性及后备箱装载便利性，确保符合家庭出行需求
- 若家中无法安装家充桩，建议重点测试你常去公共充电站的实际充电功率和兼容性

**建议尽快联系官方/到店的情况**
- 如果重复出现异常或影响正常驾驶，建议联系官方售后进一步检查

**建议下一步**
1. 我预算 20 万内，人在广州，主要城市通勤
2. 我家里不能装桩，通勤为主，偶尔长途
3. 我更看重智驾和座舱体验，帮我缩小范围

建议带上全家成员一同到店，让主要用车人实际体验后排和上下车便利性，结合ADAS、空间、续航三维度做综合决策。', NULL, NULL, '{"importedFrom":"sessions.json","order":9}'::jsonb, '2026-03-26T03:07:08.676Z');
